PAIR=[('MICROCHIP_RECTANGLE', 'MICROCHIP_SQUARE', -4862.309, 2518.712, 0.2, 1.0), ('SNACKPACK_RASPBERRY', 'SNACKPACK_VANILLA', -19.49, 243.663, 0.2, 1.0), ('GALAXY_SOUNDS_SOLAR_FLAMES', 'GALAXY_SOUNDS_SOLAR_WINDS', 655.028, 811.616, 0.2, 1.0), ('SLEEP_POD_LAMB_WOOL', 'SLEEP_POD_NYLON', 1064.969, 471.365, 0.2, 1.0)]
HEDGE=[]
CAT=[]
class Trader:
 L=10;Q=20
 def run(self,state:TradingState):
  res:Dict[str,List[Order]]={}
  try:data=json.loads(state.traderData) if state.traderData else {}
  except Exception:data={}
  hist=data.get('c',[]);h=data.get('h',{})
  mids={}
  for p,d in state.order_depths.items():
   if d.buy_orders and d.sell_orders:mids[p]=(max(d.buy_orders)+min(d.sell_orders))/2
  sh={}
  for a,b,m,s,c,t in PAIR:
   if a in mids and b in mids:
    r=mids[a]-mids[b]-m
    if abs(r)>t*s:
     v=c*r;sh[a]=sh.get(a,0)-v;sh[b]=sh.get(b,0)+v
  for a,b,beta,inter,s,c,t in HEDGE:
   if a in mids and b in mids:
    r=mids[a]-inter-beta*mids[b]
    if abs(r)>t*s:
     v=c*r;sh[a]=sh.get(a,0)-v;sh[b]=sh.get(b,0)+beta*v
  for ps,c,t in CAT:
   zs=[]
   for pp in ps:
    if pp in mids and pp in M and pp in S:zs.append((pp,(mids[pp]-M[pp]-SHIFT.get(pp,0))/S[pp]))
   if len(zs)>1:
    avg=sum(z for _,z in zs)/len(zs)
    for pp,z in zs:
     r=z-avg
     if abs(r)>t:sh[pp]=sh.get(pp,0)-c*r*S[pp]
  if 'MICROCHIP_CIRCLE' in mids:
   hist.append(mids['MICROCHIP_CIRCLE']);hist=hist[-110:]
  for lp in LEADERS:
   if lp in mids:
    a=h.get(lp,[]);a.append(mids[lp]);h[lp]=a[-501:]
  for p,d in state.order_depths.items():
   if p not in MODE or not d.buy_orders or not d.sell_orders:
    res[p]=[];continue
   if MODE[p]=='static':
    fair=M[p]+SHIFT.get(p,0)+sh.get(p,0);take=Z[p]*S[p];edge=EDGE[p]
   else:
    fair=mids[p]+SHIFT.get(p,0)+sh.get(p,0);take=10**9;edge=EDGE[p]
    if p=='MICROCHIP_OVAL' and len(hist)>50:
     fair+=1.25*0.067*(hist[-1]-hist[-51]);take=5.5
    elif p=='MICROCHIP_SQUARE' and len(hist)>100:
     fair+=0.75*0.138*(hist[-1]-hist[-101]);take=6.0

   if p in SIG:
    for lp,lag,k in SIG[p]:
     a=h.get(lp,[])
     if len(a)>lag:fair+=k*(a[-1]-a[-1-lag])
   res[p]=self.tr(p,d,int(state.position.get(p,0)),fair,take,edge,IMP[p])
  return res,0,json.dumps({'c':hist,'h':h},separators=(',',':'))
 def tr(self,p,d,pos,fair,take,edge,imp):
  bb=max(d.buy_orders);ba=min(d.sell_orders);bc=max(0,self.L-pos);sc=max(0,self.L+pos);out=[]
  if p in WALK and bc>0:
   for px in sorted(d.sell_orders):
    if px>fair-take or bc<=0:break
    q=min(bc,self.Q,-int(d.sell_orders[px]))
    if q>0:out.append(Order(p,px,q));bc-=q
  elif bc>0 and ba<=fair-take:
   q=min(bc,self.Q,-int(d.sell_orders[ba]))
   if q>0:out.append(Order(p,ba,q));bc-=q
  if p in WALK and sc>0:
   for px in sorted(d.buy_orders,reverse=True):
    if px<fair+take or sc<=0:break
    q=min(sc,self.Q,int(d.buy_orders[px]))
    if q>0:out.append(Order(p,px,-q));sc-=q
  elif sc>0 and bb>=fair+take:
   q=min(sc,self.Q,int(d.buy_orders[bb]))
   if q>0:out.append(Order(p,bb,-q));sc-=q
  if ba-bb>2*imp:bid,ask=bb+imp,ba-imp
  elif ba-bb>1:bid,ask=bb+1,ba-1
  else:bid,ask=bb,ba
  if bc>0 and bid<=fair-edge:out.append(Order(p,bid,min(self.Q,bc)))
  if sc>0 and ask>=fair+edge:out.append(Order(p,ask,-min(self.Q,sc)))
  return out
